const p = msg.payload || {};
const action = String(p.action || "").trim().toLowerCase();
const role = String(p.role || "").trim();
const acltype = String(p.acltype || "").trim();
const topic = String(p.topic || "").trim();
const allowText = String(p.allow || "true").trim().toLowerCase();
const allow = !(allowText === "false" || allowText === "0" || allowText === "deny");
if (!action || !role) return { payload: "Action and role are required", _statusOnly: true };
let cmd = null;
if (action === "deleterole") {
    cmd = { command: "deleteRole", rolename: role };
} else if (action === "addacl") {
    if (!acltype || !topic) return { payload: "ACL type and topic are required for addAcl", _statusOnly: true };
    cmd = { command: "addRoleACL", rolename: role, acltype, topic, allow };
} else if (action === "removeacl") {
    if (!acltype || !topic) return { payload: "ACL type and topic are required for removeAcl", _statusOnly: true };
    cmd = { command: "removeRoleACL", rolename: role, acltype, topic, allow };
} else {
    return { payload: "Unsupported action. Use addAcl/removeAcl/deleteRole", _statusOnly: true };
}
msg.payload = cmd;
msg.intent = "role_action";
return msg;

const username = String((msg.payload || {}).username || "").trim();
if (!username) return { payload: "Provide a client username", _statusOnly: true };
flow.set("telemetrySelectedClient", username);
flow.set("resolveState", null);
msg.payload = { command: "getClient", username };
msg.intent = "resolve_topics_get_client";
return msg;

const busy = !!flow.get("dynsecBusy");
if (busy) {
    return [null, { payload: "Another dynsec request is in progress. Wait for response/timeout." }];
}
const cmd = (msg.payload && msg.payload.command) ? msg.payload.command : "unknown";
flow.set("dynsecBusy", true);
flow.set("dynsecSince", Date.now());
flow.set("dynsecPending", cmd);
flow.set("dynsecIntent", msg.intent || null);
return [msg, { payload: "Sending dynsec command: " + cmd }];

msg.topic = "$CONTROL/dynamic-security/v1";
msg.payload = JSON.stringify({ commands: [msg.payload] });
return msg;

function arr(v) { return Array.isArray(v) ? v : (v == null ? [] : [v]); }
function boolAllow(v) {
    if (typeof v === 'boolean') return v;
    if (typeof v === 'number') return v !== 0;
    const s = String(v || '').toLowerCase();
    return !(s === 'false' || s === '0' || s === 'deny');
}
function extractClients(resp) {
    let raw = [];
    if (resp && resp.data && Array.isArray(resp.data.clients)) raw = resp.data.clients;
    else if (resp && Array.isArray(resp.clients)) raw = resp.clients;
    else if (resp && Array.isArray(resp.data)) raw = resp.data;
    const out = [];
    for (const c of raw) {
        if (typeof c === 'string') out.push({ username: c });
        else if (c && typeof c === 'object') out.push({
            username: c.username || c.clientid || c.clientId || c.name || 'unknown',
            disabled: !!(c.disabled === true),
            roles: arr(c.roles).map(r => (typeof r === 'string' ? r : (r.rolename || r.role || ''))).filter(Boolean),
            groups: arr(c.groups).map(g => (typeof g === 'string' ? g : (g.groupname || g.group || ''))).filter(Boolean)
        });
    }
    return out;
}
function extractRoles(resp) {
    let raw = [];
    if (resp && resp.data && Array.isArray(resp.data.roles)) raw = resp.data.roles;
    else if (resp && Array.isArray(resp.roles)) raw = resp.roles;
    else if (resp && Array.isArray(resp.data)) raw = resp.data;
    return raw.map(r => {
        if (typeof r === 'string') return { rolename: r };
        return { rolename: r.rolename || r.role || r.name || 'unknown', acls: arr(r.acls) };
    });
}
function extractClientRoles(resp) {
    const c = (resp && resp.data && (resp.data.client || resp.data)) || resp || {};
    const roles = arr(c.roles).map(r => (typeof r === 'string' ? r : (r.rolename || r.role || ''))).filter(Boolean);
    return [...new Set(roles)];
}
function extractAllowedTopicsFromRole(resp) {
    const roleObj = (resp && resp.data && (resp.data.role || resp.data)) || resp || {};
    const acls = arr(roleObj.acls);
    const allowed = [];
    for (const acl of acls) {
        if (!acl || typeof acl !== 'object') continue;
        const acltype = String(acl.acltype || acl.aclType || acl.type || '').trim();
        const topic = String(acl.topic || acl.topicFilter || acl.pattern || '').trim();
        const allow = boolAllow(acl.allow ?? acl.access);
        if (!allow || !topic) continue;
        if (acltype === 'subscribePattern' || acltype === 'subscribeLiteral') {
            allowed.push(topic);
        }
    }
    return [...new Set(allowed)];
}

let payload = msg.payload;
if (typeof payload === 'string') {
    try { payload = JSON.parse(payload); } catch (e) {
        flow.set('dynsecBusy', false);
        return [
            { payload: 'Failed to parse dynsec JSON response' },
            null, null, null, null, null,
            { payload: String(msg.payload).slice(0, 4000) },
            null
        ];
    }
}

const responses = arr(payload.responses && payload.responses.length ? payload.responses : payload);
let statusText = 'Response received';
let usersText = null;
let rolesText = null;
let topicsText = null;
let followup = null;
let release = true;
const pendingIntent = flow.get('dynsecIntent');

for (const r of responses) {
    const cmd = String((r && r.command) || flow.get('dynsecPending') || '').trim();
    const error = (r && (r.error || r.err || r.message && /error/i.test(String(r.message)))) ? (r.error || r.err || r.message) : null;
    if (error) statusText = 'ERROR: ' + String(error);
    else if (cmd) statusText = 'OK: ' + cmd;

    if (cmd === 'listClients') {
        const clients = extractClients(r);
        flow.set('clientCache', clients);
        const lines = clients.map(c => {
            const rs = (c.roles || []).join(', ') || '-';
            const gs = (c.groups || []).join(', ') || '-';
            return '- ' + c.username + ' | disabled=' + (!!c.disabled) + ' | roles=' + rs + ' | groups=' + gs;
        });
        usersText = lines.length ? lines.join('\n') : 'No clients found';
    }

    if (cmd === 'listRoles') {
        const roles = extractRoles(r);
        flow.set('roleCache', roles);
        const lines = roles.map(role => {
            const ac = arr(role.acls).length;
            return '- ' + role.rolename + ' | ACLs=' + ac;
        });
        rolesText = lines.length ? lines.join('\n') : 'No roles found';
    }

    if (pendingIntent === 'resolve_topics_get_client' && cmd === 'getClient') {
        const selected = flow.get('telemetrySelectedClient') || '';
        const roles = extractClientRoles(r);
        const state = { client: selected, roles, idx: 0, topics: [] };
        flow.set('resolveState', state);
        if (roles.length === 0) {
            const map = flow.get('allowedTopicsMap') || {};
            map[selected] = [];
            flow.set('allowedTopicsMap', map);
            topicsText = selected + ': no subscribe roles found';
            release = true;
        } else {
            release = false;
            flow.set('dynsecIntent', 'resolve_topics_get_role');
            flow.set('dynsecPending', 'getRole:' + roles[0]);
            followup = { payload: { command: 'getRole', rolename: roles[0] } };
            statusText = 'Resolving topics for ' + selected + ' (' + roles.length + ' roles)';
        }
    } else if (pendingIntent === 'resolve_topics_get_role' && cmd === 'getRole') {
        const state = flow.get('resolveState') || null;
        if (state && Array.isArray(state.roles) && state.idx < state.roles.length) {
            const allowed = extractAllowedTopicsFromRole(r);
            state.topics = [...new Set(state.topics.concat(allowed))];
            state.idx += 1;
            if (state.idx < state.roles.length) {
                release = false;
                flow.set('resolveState', state);
                const nextRole = state.roles[state.idx];
                flow.set('dynsecPending', 'getRole:' + nextRole);
                followup = { payload: { command: 'getRole', rolename: nextRole } };
            } else {
                const map = flow.get('allowedTopicsMap') || {};
                map[state.client] = [...new Set(state.topics)].sort();
                flow.set('allowedTopicsMap', map);
                topicsText = state.client + ':\n' + (map[state.client].length ? map[state.client].map(t => '- ' + t).join('\n') : 'No subscribe ACL topics found');
                flow.set('resolveState', null);
                release = true;
            }
        }
    }
}

if (release) {
    flow.set('dynsecBusy', false);
    flow.set('dynsecSince', null);
    flow.set('dynsecPending', null);
    flow.set('dynsecIntent', null);
}

const rawText = JSON.stringify(payload, null, 2).slice(0, 4000);
return [
    { payload: statusText },
    usersText ? { payload: usersText } : null,
    rolesText ? { payload: rolesText } : null,
    null,
    null,
    topicsText ? { payload: topicsText } : null,
    { payload: rawText },
    followup
];

const busy = !!flow.get('dynsecBusy');
if (!busy) return null;
const since = Number(flow.get('dynsecSince') || 0);
if (!since) return null;
if (Date.now() - since < 12000) return null;
flow.set('dynsecBusy', false);
flow.set('dynsecSince', null);
flow.set('dynsecPending', null);
flow.set('dynsecIntent', null);
flow.set('resolveState', null);
return { payload: 'Timeout waiting for dynsec response (12s). Request state cleared.' };

function mqttMatch(filter, topic) {
    const f = String(filter || '').split('/');
    const t = String(topic || '').split('/');
    let i = 0;
    for (; i < f.length; i++) {
        if (f[i] === '#') return true;
        if (f[i] === '+') {
            if (i >= t.length) return false;
            continue;
        }
        if (i >= t.length || f[i] !== t[i]) return false;
    }
    return i === t.length;
}
const selected = flow.get('telemetrySelectedClient');
if (!selected) return null;
const map = flow.get('allowedTopicsMap') || {};
const filters = map[selected] || [];
if (!filters.length) return null;
const topic = String(msg.topic || '');
const allowed = filters.some(f => mqttMatch(f, topic));
if (!allowed) return null;
const ts = new Date().toISOString();
let body = msg.payload;
if (typeof body !== 'string') {
    try { body = JSON.stringify(body); } catch (e) { body = String(body); }
}
const line = ts + ' | ' + topic + ' | ' + body;
